CA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA,iBAAiB;AACjB;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA,iBAAiB;AACjB;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA,kBAAkB;AAClB,IAAI,KAAU;AACd;AACA;AACA;AACA;AACA,C;;;;;;;AChnCA;AACA,yBAAyB,mBAAO,CAAC,uDAA+D;AAChG;AACA,qBAAqB,mBAAO,CAAC,0ZAA4W;AACzY;AACA,uBAAuB,mBAAO,CAAC,+OAAoO;AACnQ;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;;AAEA;AACA,IAAI,KAAU,GAAG;AACjB;AACA;AACA;AACA;AACA;AACA;AACA,GAAG;AACH;AACA;AACA;AACA;AACA,GAAG;AACH,CAAC;;AAED","file":"95.js","sourcesContent":["<template>\r\n    <el-dialog\r\n        :title=\"titleDialog\"\r\n        :visible=\"showDialog\"\r\n        @close=\"close\"\r\n        @open=\"create\"\r\n        append-to-body\r\n        @opened=\"opened\"\r\n        :close-on-click-modal=\"false\"\r\n    >\r\n        <form autocomplete=\"off\" @submit.prevent=\"submit\">\r\n            <div class=\"form-body\">\r\n                <div class=\"row\">\r\n                    <!-- <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.seller_id }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Vendedor - Asesor\r\n                                <span class=\"text-danger\">*</span></label\r\n                            >\r\n                            <el-select\r\n                                v-model=\"form.seller_id\"\r\n                                filterable\r\n                                @change=\"filterProvince\"\r\n                                popper-class=\"el-select-departments\"\r\n                                dusk=\"department_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in all_users\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.name\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.seller_id\"\r\n                                v-text=\"errors.seller_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div> -->\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{\r\n                                'has-danger': errors.identity_document_type_id\r\n                            }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Tipo Doc. Identidad\r\n                                <span class=\"text-danger\">*</span></label\r\n                            >\r\n                            <el-select\r\n                                v-model=\"form.identity_document_type_id\"\r\n                                filterable\r\n                                popper-class=\"el-select-identity_document_type\"\r\n                                dusk=\"identity_document_type_id\"\r\n                                @change=\"changeIdentityDocType\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in identity_document_types\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.identity_document_type_id\"\r\n                                v-text=\"errors.identity_document_type_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.number }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Número\r\n                                <span class=\"text-danger\">*</span></label\r\n                            >\r\n\r\n                            <div v-if=\"api_service_token != false\">\r\n                                <x-input-service\r\n                                    :identity_document_type_id=\"\r\n                                        form.identity_document_type_id\r\n                                    \"\r\n                                    v-model=\"form.number\"\r\n                                    @search=\"searchNumber\"\r\n                                ></x-input-service>\r\n                            </div>\r\n                            <div v-else>\r\n                                <el-input\r\n                                    v-model=\"form.number\"\r\n                                    :maxlength=\"maxLength\"\r\n                                    dusk=\"number\"\r\n                                >\r\n                                    <template\r\n                                        v-if=\"\r\n                                            form.identity_document_type_id ===\r\n                                                '6' ||\r\n                                                form.identity_document_type_id ===\r\n                                                    '1'\r\n                                        \"\r\n                                    >\r\n                                        <el-button\r\n                                            type=\"primary\"\r\n                                            slot=\"append\"\r\n                                            :loading=\"loading_search\"\r\n                                            icon=\"el-icon-search\"\r\n                                            @click.prevent=\"searchCustomer\"\r\n                                        >\r\n                                        </el-button>\r\n                                    </template>\r\n                                    <i\r\n                                        slot=\"prefix\"\r\n                                        class=\"el-icon-edit-outline\"\r\n                                    ></i\r\n                                ></el-input>\r\n                            </div>\r\n\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.number\"\r\n                                v-text=\"errors.number[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.name }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Nombre\r\n                                <span class=\"text-danger\">*</span></label\r\n                            >\r\n                            <el-input v-model=\"form.name\" dusk=\"name\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.name\"\r\n                                v-text=\"errors.name[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.trade_name }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Nombre comercial</label\r\n                            >\r\n                            <el-input\r\n                                v-model=\"form.trade_name\"\r\n                                dusk=\"trade_name\"\r\n                            >\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.trade_name\"\r\n                                v-text=\"errors.trade_name[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n\r\n                <!-- <div class=\"row\" v-if=\"type === 'customers'\">\r\n                    <div class=\"col-md-4\">\r\n                        <div class=\"form-group\" :class=\"{'has-danger': errors.person_type_id}\">\r\n                            <label class=\"control-label\">Tipo de cliente</label>\r\n                            <el-select v-model=\"form.person_type_id\" filterable  >\r\n                                <el-option v-for=\"option in person_types\" :key=\"option.id\" :value=\"option.id\" :label=\"option.description\"></el-option>\r\n                            </el-select>\r\n                            <small class=\"text-danger\" v-if=\"errors.person_type_id\" v-text=\"errors.person_type_id[0]\"></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-8\">\r\n                        <div class=\"form-group\"  >\r\n                            <label class=\"control-label\">Comentario</label>\r\n                            <el-input v-model=\"form.comment\"> <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i></el-input>\r\n                        </div>\r\n                    </div>\r\n                </div> -->\r\n\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.country_id }\"\r\n                        >\r\n                            <label class=\"control-label\">País</label>\r\n                            <el-select\r\n                                v-model=\"form.country_id\"\r\n                                filterable\r\n                                dusk=\"country_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in countries\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.country_id\"\r\n                                v-text=\"errors.country_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.department_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Departamento</label>\r\n                            <el-select\r\n                                v-model=\"form.department_id\"\r\n                                filterable\r\n                                @change=\"filterProvince\"\r\n                                popper-class=\"el-select-departments\"\r\n                                dusk=\"department_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in all_departments\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.department_id\"\r\n                                v-text=\"errors.department_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.province_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Provincia</label>\r\n                            <el-select\r\n                                v-model=\"form.province_id\"\r\n                                filterable\r\n                                @change=\"filterDistrict\"\r\n                                popper-class=\"el-select-provinces\"\r\n                                dusk=\"province_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in provinces\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.province_id\"\r\n                                v-text=\"errors.province_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.province_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Distrito</label>\r\n                            <el-select\r\n                                v-model=\"form.district_id\"\r\n                                filterable\r\n                                popper-class=\"el-select-districts\"\r\n                                dusk=\"district_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in districts\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.district_id\"\r\n                                v-text=\"errors.district_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-8\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.address }\"\r\n                        >\r\n                            <label class=\"control-label\">Dirección</label>\r\n                            <el-input v-model=\"form.address\" dusk=\"address\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.address\"\r\n                                v-text=\"errors.address[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.telephone }\"\r\n                        >\r\n                            <label class=\"control-label\">Teléfono</label>\r\n                            <el-input v-model=\"form.telephone\" dusk=\"telephone\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.telephone\"\r\n                                v-text=\"errors.telephone[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.email }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Correo electrónico</label\r\n                            >\r\n                            <el-input v-model=\"form.email\" dusk=\"email\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.email\"\r\n                                v-text=\"errors.email[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-6\" v-if=\"form.state\">\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\"\r\n                                >Estado del Contribuyente</label\r\n                            >\r\n                            <template v-if=\"form.state == 'ACTIVO'\">\r\n                                <el-alert\r\n                                    :title=\"`${form.state}`\"\r\n                                    type=\"success\"\r\n                                    show-icon\r\n                                    :closable=\"false\"\r\n                                ></el-alert>\r\n                            </template>\r\n                            <template v-else>\r\n                                <el-alert\r\n                                    :title=\"`${form.state}`\"\r\n                                    type=\"error\"\r\n                                    show-icon\r\n                                    :closable=\"false\"\r\n                                ></el-alert>\r\n                            </template>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\" v-if=\"form.condition\">\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\"\r\n                                >Condición del Contribuyente</label\r\n                            >\r\n                            <template v-if=\"form.condition == 'HABIDO'\">\r\n                                <el-alert\r\n                                    :title=\"`${form.condition}`\"\r\n                                    type=\"success\"\r\n                                    show-icon\r\n                                    :closable=\"false\"\r\n                                ></el-alert>\r\n                            </template>\r\n                            <template v-else>\r\n                                <el-alert\r\n                                    :title=\"`${form.condition}`\"\r\n                                    type=\"error\"\r\n                                    show-icon\r\n                                    :closable=\"false\"\r\n                                ></el-alert>\r\n                            </template>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row mt-2\" v-if=\"type === 'suppliers'\">\r\n                    <div class=\"col-md-6 center-el-checkbox\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.perception_agent }\"\r\n                        >\r\n                            <el-checkbox v-model=\"form.perception_agent\"\r\n                                >¿Es agente de percepción?</el-checkbox\r\n                            ><br />\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.perception_agent\"\r\n                                v-text=\"errors.perception_agent[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div\r\n                        class=\"col-md-6\"\r\n                        v-if=\"type === 'suppliers'\"\r\n                        v-show=\"form.perception_agent\"\r\n                    >\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\"\r\n                                >Porcentaje de percepción</label\r\n                            >\r\n\r\n                            <el-input v-model=\"form.percentage_perception\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n\r\n                <div\r\n                    class=\"row m-t-10\"\r\n                    v-for=\"(row, index) in form.addresses\"\r\n                    :key=\"index\"\r\n                >\r\n                    <div class=\"col-md-12\">\r\n                        <label class=\"control-label\" v-if=\"index === 0\">\r\n                            Dirección principal\r\n                        </label>\r\n                        <label class=\"control-label\" v-else>\r\n                            Dirección secundaria # {{ index }}\r\n                            <el-button\r\n                                size=\"mini\"\r\n                                icon=\"el-icon-minus\"\r\n                                @click.prevent=\"clickRemoveAddress(index)\"\r\n                                class=\"btn-default-danger\"\r\n                                >Eliminar dirección</el-button\r\n                            >\r\n                        </label>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.country_id }\"\r\n                        >\r\n                            <label class=\"control-label\">País</label>\r\n                            <el-select v-model=\"row.country_id\" filterable>\r\n                                <el-option\r\n                                    v-for=\"option in countries\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.country_id\"\r\n                                v-text=\"errors.country_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-8\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.location_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Ubigeo</label>\r\n                            <el-cascader\r\n                                :options=\"locations\"\r\n                                v-model=\"row.location_id\"\r\n                                :clearable=\"true\"\r\n                                filterable\r\n                            ></el-cascader>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.location_id\"\r\n                                v-text=\"errors.location_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-12\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.address }\"\r\n                        >\r\n                            <label class=\"control-label\">Dirección</label>\r\n                            <el-input v-model=\"row.address\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.address\"\r\n                                v-text=\"errors.address[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.phone }\"\r\n                        >\r\n                            <label class=\"control-label\">Teléfono</label>\r\n                            <el-input v-model=\"row.phone\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.phone\"\r\n                                v-text=\"errors.phone[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.email }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Correo electrónico</label\r\n                            >\r\n                            <el-input v-model=\"row.email\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.email\"\r\n                                v-text=\"errors.email[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <!-- <div class=\"row\">\r\n                    <div class=\"col-md-4\">\r\n                        <label class=\"control-label\">Llegó de</label>\r\n                        <el-select clearable v-model=\"form.social_media_id\">\r\n                            <el-option\r\n                                v-for=\"(dta, idx) in social_medias\"\r\n                                :key=\"idx\"\r\n                                :label=\"dta.description\"\r\n                                :value=\"dta.id\"\r\n                            >\r\n                            </el-option>\r\n                        </el-select>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <label class=\"control-label\">Cat Vip</label>\r\n                        <el-select clearable v-model=\"form.social_media_id\">\r\n                            <el-option\r\n                                v-for=\"(dta, idx) in social_medias\"\r\n                                :key=\"idx\"\r\n                                :label=\"dta.description\"\r\n                                :value=\"dta.id\"\r\n                            >\r\n                            </el-option>\r\n                        </el-select>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <label class=\"control-label\">Mensualidad</label>\r\n                        <el-input clearable v-model=\"form.vip_amount\" />\r\n                    </div>\r\n                </div> -->\r\n            </div>\r\n            <div class=\"form-actions text-end pt-2 pb-2\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button\r\n                    type=\"primary\"\r\n                    native-type=\"submit\"\r\n                    :loading=\"loading_submit\"\r\n                    >Guardar</el-button\r\n                >\r\n            </div>\r\n        </form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nimport { serviceNumber } from \"../../mixins/functions\";\r\n\r\nexport default {\r\n    mixins: [serviceNumber],\r\n    props: [\r\n        \"worker\",\r\n        \"showDialog\",\r\n        \"type\",\r\n        \"recordId\",\r\n        \"external\",\r\n        \"document_type_id\",\r\n        \"input_person\",\r\n        \"user_id\"\r\n    ],\r\n    data() {\r\n        return {\r\n            social_medias: [],\r\n            loading_submit: false,\r\n            titleDialog: null,\r\n            resource: this.worker ? \"restaurant/worker/persons\" : \"persons\",\r\n            errors: {},\r\n            api_service_token: false,\r\n            form: {},\r\n            countries: [],\r\n            all_departments: [],\r\n            all_provinces: [],\r\n            all_districts: [],\r\n            provinces: [],\r\n            districts: [],\r\n            locations: [],\r\n            person_types: [],\r\n            identity_document_types: [],\r\n            all_users: []\r\n        };\r\n    },\r\n    async created() {\r\n        await this.initForm();\r\n        await this.$http.get(`/${this.resource}/tables`).then(response => {\r\n            this.api_service_token = response.data.api_service_token;\r\n            this.social_medias = response.data.social_media;\r\n            this.all_users = response.data.users;\r\n            this.countries = response.data.countries;\r\n            this.all_departments = response.data.departments;\r\n            this.all_provinces = response.data.provinces;\r\n            this.all_districts = response.data.districts;\r\n            this.identity_document_types =\r\n                response.data.identity_document_types;\r\n            this.locations = response.data.locations;\r\n            this.person_types = response.data.person_types;\r\n        });\r\n    },\r\n    computed: {\r\n        maxLength: function() {\r\n            if (this.form.identity_document_type_id === \"6\") {\r\n                return 11;\r\n            }\r\n            if (this.form.identity_document_type_id === \"1\") {\r\n                return 8;\r\n            }\r\n        }\r\n    },\r\n    methods: {\r\n        nuevoMetodo(){\r\n            let admin = this.all_users.find(user => user.type == \"admin\");\r\n            if (admin) {\r\n                this.form.seller_id = admin.id;\r\n            } else {\r\n                if (this.all_users.length != 0) {\r\n                    this.form.seller_id = this.all_users[0].id;\r\n                }\r\n            }\r\n        },\r\n        initForm() {\r\n            this.errors = {};\r\n            this.form = {\r\n                id: null,\r\n                type: this.type,\r\n                identity_document_type_id: \"6\",\r\n                number: \"\",\r\n                name: null,\r\n                trade_name: null,\r\n                country_id: \"PE\",\r\n                department_id: null,\r\n                province_id: null,\r\n                district_id: null,\r\n                address: null,\r\n                telephone: null,\r\n                condition: null,\r\n                state: null,\r\n                email: null,\r\n                perception_agent: false,\r\n                percentage_perception: 0,\r\n                person_type_id: null,\r\n                comment: null,\r\n                addresses: [],\r\n                seller_id: null\r\n            };\r\n        },\r\n        async opened() {\r\n            // this.form.seller_id = this.user_id;\r\n            if (this.external && this.input_person) {\r\n                if (\r\n                    this.form.number.length === 8 ||\r\n                    this.form.number.length === 11\r\n                ) {\r\n                    if (this.api_service_token != false) {\r\n                        await this.$eventHub.$emit(\"enableClickSearch\");\r\n                    } else {\r\n                        this.searchCustomer();\r\n                    }\r\n                }\r\n            }\r\n        },\r\n        create() {\r\n            if (this.external) {\r\n                if (this.document_type_id === \"01\") {\r\n                    this.form.identity_document_type_id = \"6\";\r\n                }\r\n                if (this.document_type_id === \"03\") {\r\n                    this.form.identity_document_type_id = \"1\";\r\n                }\r\n\r\n                if (this.input_person) {\r\n                    this.form.identity_document_type_id = this.input_person\r\n                        .identity_document_type_id\r\n                        ? this.input_person.identity_document_type_id\r\n                        : this.form.identity_document_type_id;\r\n                    this.form.number = this.input_person.number\r\n                        ? this.input_person.number\r\n                        : \"\";\r\n                }\r\n            }\r\n            if (this.type === \"customers\") {\r\n                this.titleDialog = this.recordId\r\n                    ? \"Editar Cliente\"\r\n                    : \"Nuevo Cliente\";\r\n            }\r\n            if (this.type === \"suppliers\") {\r\n                this.titleDialog = this.recordId\r\n                    ? \"Editar Proveedor\"\r\n                    : \"Nuevo Proveedor\";\r\n            }\r\n\r\n            if (this.recordId) {\r\n                this.$http\r\n                    .get(`/${this.resource}/record/${this.recordId}`)\r\n                    .then(response => {\r\n                        this.form = response.data.data;\r\n                        this.filterProvinces();\r\n                        this.filterDistricts();\r\n                    });\r\n            }\r\n            \r\n        },\r\n        clickAddAddress() {\r\n            /* this.form.more_address.push({\r\n                    location_id: [],\r\n                    address: null,\r\n                })*/\r\n\r\n            this.form.addresses.push({\r\n                id: null,\r\n                country_id: \"PE\",\r\n                location_id: [],\r\n                address: null,\r\n                email: null,\r\n                phone: null,\r\n                main: false\r\n            });\r\n        },\r\n        submit() {\r\n            this.nuevoMetodo();\r\n            if (!this.form.seller_id) {\r\n                this.$message.error(\"Debe seleccionar un asesor\");\r\n                return;\r\n            }\r\n            if (\r\n                this.form.identity_document_type_id == \"6\" &&\r\n                this.form.number.length != 11\r\n            ) {\r\n                this.$message.error(\"La longitud del RUC debe ser de 11\");\r\n                return;\r\n            }\r\n            if (\r\n                this.form.identity_document_type_id == \"1\" &&\r\n                this.form.number.length != 8\r\n            ) {\r\n                this.$message.error(\"La longitud del DNI debe ser de 8\");\r\n                return;\r\n            }\r\n            this.loading_submit = true;\r\n            this.$http\r\n                .post(`/${this.resource}`, this.form)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$message.success(response.data.message);\r\n                        this.$emit(\"add_customer\", response.data.id);\r\n                        if (this.external) {\r\n                            this.$eventHub.$emit(\r\n                                \"reloadDataPersons\",\r\n                                response.data.id\r\n                            );\r\n                        } else {\r\n                            this.$eventHub.$emit(\"reloadData\");\r\n                        }\r\n                        this.close();\r\n                    } else {\r\n                        this.$message.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        console.log(error.response.data.errors);\r\n                        this.errors = error.response.data.errors;\r\n                    } else {\r\n                        console.log(error);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false;\r\n                });\r\n        },\r\n        changeIdentityDocType() {\r\n            this.recordId == null ? this.setDataDefaultCustomer() : null;\r\n        },\r\n        setDataDefaultCustomer() {\r\n            if (this.form.identity_document_type_id == \"0\") {\r\n                this.form.number = \"99999999\";\r\n                this.form.name = \"Clientes - Varios\";\r\n            } else {\r\n                this.form.number = \"\";\r\n                this.form.name = null;\r\n            }\r\n        },\r\n        close() {\r\n            this.$eventHub.$emit(\"initInputPerson\");\r\n            this.$emit(\"update:showDialog\", false);\r\n            this.initForm();\r\n        },\r\n        searchCustomer() {\r\n            this.searchServiceNumberByType();\r\n        },\r\n\r\n        searchNumber(data) {\r\n            this.form.district_id = data.ubigeo[2];\r\n            this.filterDistricts();\r\n            this.form.name =\r\n                this.form.identity_document_type_id === \"1\"\r\n                    ? data.nombre_completo\r\n                    : data.nombre_o_razon_social;\r\n            this.form.trade_name =\r\n                this.form.identity_document_type_id === \"6\"\r\n                    ? data.nombre_o_razon_social\r\n                    : \"\";\r\n            this.form.location_id = data.ubigeo;\r\n            this.form.department_id = data.ubigeo ? data.ubigeo[0] : null;\r\n            this.form.province_id = data.ubigeo ? data.ubigeo[1] : null;\r\n            this.form.district_id = data.ubigeo ? data.ubigeo[2] : null;\r\n            this.filterProvinces();\r\n            this.filterDistricts();\r\n            this.form.address = data.direccion;\r\n            this.form.condition = data.condicion;\r\n            this.form.state = data.estado;\r\n        },\r\n        clickRemoveAddress(index) {\r\n            this.form.addresses.splice(index, 1);\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/persons/form.vue","var render = function() {\n  var _vm = this\n  var _h = _vm.$createElement\n  var _c = _vm._self._c || _h\n  return _c(\n    \"el-dialog\",\n    {\n      attrs: {\n        title: _vm.titleDialog,\n        visible: _vm.showDialog,\n        \"append-to-body\": \"\",\n        \"close-on-click-modal\": false\n      },\n      on: { close: _vm.close, open: _vm.create, opened: _vm.opened }\n    },\n    [\n      _c(\n        \"form\",\n        {\n          attrs: { autocomplete: \"off\" },\n          on: {\n            submit: function($event) {\n              $event.preventDefault()\n              return _vm.submit.apply(null, arguments)\n            }\n          }\n        },\n        [\n          _c(\n            \"div\",\n            { staticClass: \"form-body\" },\n            [\n              _c(\"div\", { staticClass: \"row\" }, [\n                _c(\"div\", { staticClass: \"col-md-6\" }, [\n                  _c(\n                    \"div\",\n                    {\n                      staticClass: \"form-group\",\n                      class: {\n                        \"has-danger\": _vm.errors.identity_document_type_id\n                      }\n                    },\n                    [\n                      _c(\"label\", { staticClass: \"control-label\" }, [\n                        _vm._v(\n                          \"Tipo Doc. Identidad\\n                            \"\n                        ),\n                        _c(\"span\", { staticClass: \"text-danger\" }, [\n                          _vm._v(\"*\")\n                        ])\n                      ]),\n                      _vm._v(\" \"),\n                      _c(\n                        \"el-select\",\n                        {\n                          attrs: {\n 